INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('40c8418c-ac9f-4eba-bf48-17e2189f4a56', '5939e491-1522-4b87-95c7-10c36409530c', 0, 0, '# 液压系统故障知识库\n\n## 1. 液压系统无压力\n\n### 故障现象\n- 系统启动后压力表显示无压力\n- 执行机构不动作\n- 液压泵声音异常\n\n### 可能原因\n1. 液压泵故障（泵内磨损、轴断裂）\n2. 油箱液位过低\n3. 吸油管路堵塞或漏气\n4. 溢流阀故障（阀芯卡住、弹簧断裂）\n5. 换向阀故障（阀芯未复位）\n6. 油液粘度不当');
-- TODO: 添加向量嵌入 (chunk_id: 40c8418c-ac9f-4eba-bf48-17e2189f4a56)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('6419773c-8064-4d9d-8c41-389ba782b95f', '5939e491-1522-4b87-95c7-10c36409530c', 1, 0, '### 故障树结构\n```\n顶事件：液压系统无压力\n├── OR\n│   ├── 泵故障\n│   │   ├── OR\n│   │   │   ├── 泵内磨损\n│   │   │   ├── 泵轴断裂\n│   │   │   └── 泵反转\n│   │   └── 泵电机故障\n│   ├── 油箱问题\n│   │   ├── OR\n│   │   │   ├── 油位过低\n│   │   │   └── 油液污染\n│   │   └── 油液粘度不当\n│   ├── 吸油管路问题\n│   │   ├── OR\n│   │   │   ├── 吸油管堵塞\n│   │   │   ├── 吸油管漏气\n│   │   │   └── 过滤器堵塞\n│   │   └── 空气进入系统\n│   └── 控制阀故障\n│       ├── OR\n│       │   ├── 溢流阀故障\n│       │   ├── 换向阀故障\n│       │   └── 顺序阀故障\n│       └── 阀芯卡滞\n```');
-- TODO: 添加向量嵌入 (chunk_id: 6419773c-8064-4d9d-8c41-389ba782b95f)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('b376ba76-7251-4b99-94c0-32c603c90c52', '5939e491-1522-4b87-95c7-10c36409530c', 2, 0, '### 维修建议\n1. 检查油箱液位\n2. 检查泵运转声音\n3. 检查溢流阀设定压力\n4. 检查吸油管路是否漏气\n\n---\n\n## 2. 液压系统压力不足\n\n### 故障现象\n- 压力表显示压力低于设定值\n- 执行机构动作缓慢\n- 液压缸爬行\n\n### 可能原因\n1. 溢流阀设定压力过低\n2. 泵内磨损导致内泄\n3. 油液温度过高导致粘度下降\n4. 液压缸内泄\n5. 控制阀内泄\n6. 油液污染');
-- TODO: 添加向量嵌入 (chunk_id: b376ba76-7251-4b99-94c0-32c603c90c52)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('477c399d-ddf2-4512-abb3-d55a139bd6d2', '5939e491-1522-4b87-95c7-10c36409530c', 3, 0, '### 故障树结构\n```\n顶事件：液压系统压力不足\n├── OR\n│   ├── 泵问题\n│   │   ├── OR\n│   │   │   ├── 泵内磨损\n│   │   │   ├── 泵转速不足\n│   │   │   └── 泵选型不当\n│   │   └── 泵效率下降\n│   ├── 溢流阀问题\n│   │   ├── OR\n│   │   │   ├── 设定压力过低\n│   │   │   └── 阀内泄漏\n│   │   └── 弹簧疲劳\n│   ├── 执行机构内泄\n│   │   ├── OR\n│   │   │   ├── 液压缸内泄\n│   │   │   └── 液压马达内泄\n│   │   └── 密封件损坏\n│   └── 油液问题\n│       ├── OR\n│       │   ├── 油温过高\n│       │   └── 油液污染\n│       └── 粘度降低\n```\n\n---\n\n## 3. 液压系统压力过高\n\n### 故障现象\n- 压力表显示压力超过设定值\n- 液压泵噪音大\n- 管路振动\n- 液压缸动作不平稳');
-- TODO: 添加向量嵌入 (chunk_id: 477c399d-ddf2-4512-abb3-d55a139bd6d2)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('53b4f046-d519-4a6c-bcae-55fda7d48bfb', '5939e491-1522-4b87-95c7-10c36409530c', 4, 0, '### 可能原因\n1. 溢流阀设定压力过高\n2. 溢流阀阀芯卡住\n3. 负载过大\n4. 换向阀故障\n5. 顺序阀设定不当\n\n### 故障树结构\n```\n顶事件：液压系统压力过高\n├── OR\n│   ├── 溢流阀故障\n│   │   ├── OR\n│   │   │   ├── 设定压力过高\n│   │   │   ├── 阀芯卡住\n│   │   │   └── 弹簧断裂\n│   │   └── 阀内堵塞\n│   ├── 负载问题\n│   │   ├── AND\n│   │   │   ├── 负载过大\n│   │   │   └── 安全阀未打开\n│   │   └── 负载锁定\n│   └── 阀故障\n│       ├── 换向阀故障\n│       └── 顺序阀设定不当\n```\n\n---\n\n## 4. 液压缸动作缓慢\n\n### 故障现象\n- 液压缸伸出/回缩速度慢\n- 多个液压缸速度不一致\n- 动作有停顿\n\n### 可能原因\n1. 泵流量不足\n2. 油液粘度不当\n3. 液压缸内泄\n4. 控制阀开口过小\n5. 负载过大\n6. 空气进入系统');
-- TODO: 添加向量嵌入 (chunk_id: 53b4f046-d519-4a6c-bcae-55fda7d48bfb)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('bebac1cc-1095-4c6e-b5e4-63183b79c6fe', '5939e491-1522-4b87-95c7-10c36409530c', 5, 0, '### 故障树结构\n```\n顶事件：液压缸动作缓慢\n├── OR\n│   ├── 泵流量不足\n│   │   ├── OR\n│   │   │   ├── 泵磨损\n│   │   │   ├── 泵转速低\n│   │   │   └── 油温过高\n│   │   └── 吸油不足\n│   ├── 液压缸问题\n│   │   ├── OR\n│   │   │   ├── 液压缸内泄\n│   │   │   └── 密封件损坏\n│   │   └── 活塞杆弯曲\n│   ├── 控制阀问题\n│   │   ├── OR\n│   │   │   ├── 阀开口过小\n│   │   │   └── 阀内泄漏\n│   │   └── 阀芯卡滞\n│   ├── 负载过大\n│   └── 系统进气\n│       └── 空气进入\n```\n\n---\n\n## 5. 液压油温过高\n\n### 故障现象\n- 油温表显示温度超过70°C\n- 液压系统效率下降\n- 密封件老化加快\n- 油液变色');
-- TODO: 添加向量嵌入 (chunk_id: bebac1cc-1095-4c6e-b5e4-63183b79c6fe)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('f0c5d28c-c681-4399-98c8-60d3aaeebe74', '5939e491-1522-4b87-95c7-10c36409530c', 6, 0, '### 可能原因\n1. 冷却器故障（风扇/水冷堵塞）\n2. 油箱散热不良\n3. 溢流阀频繁工作\n4. 油液不足\n5. 油液污染\n6. 泵内磨损');
-- TODO: 添加向量嵌入 (chunk_id: f0c5d28c-c681-4399-98c8-60d3aaeebe74)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('ec308491-89db-4e26-a6a4-017c5cb2e728', '5939e491-1522-4b87-95c7-10c36409530c', 7, 0, '### 故障树结构\n```\n顶事件：液压油温过高\n├── OR\n│   ├── 冷却系统故障\n│   │   ├── OR\n│   │   │   ├── 冷却器堵塞\n│   │   │   ├── 冷却风扇故障\n│   │   │   └── 水冷系统故障\n│   │   └── 冷却面积不足\n│   ├── 溢流阀频繁工作\n│   │   ├── OR\n│   │   │   ├── 系统压力设定过高\n│   │   │   ├── 负载过大\n│   │   │   └── 阀内泄漏\n│   │   └── 压力波动\n│   ├── 油箱问题\n│   │   ├── 油液不足\n│   │   └── 散热不良\n│   ├── 油液问题\n│   │   ├── OR\n│   │   │   ├── 油液污染\n│   │   │   └── 油液老化\n│   │   └── 粘度不当\n│   └── 泵问题\n│       └── 泵内磨损导致内泄\n```\n\n---\n\n## 6. 液压系统噪音过大\n\n### 故障现象\n- 泵噪音异常\n- 管路振动\n- 气蚀声音\n- 液压缸冲击');
-- TODO: 添加向量嵌入 (chunk_id: ec308491-89db-4e26-a6a4-017c5cb2e728)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('cf178aec-e2af-47ba-b103-6add6752eb76', '5939e491-1522-4b87-95c7-10c36409530c', 8, 0, '### 故障现象\n- 泵噪音异常\n- 管路振动\n- 气蚀声音\n- 液压缸冲击\n\n### 可能原因\n1. 泵内气蚀\n2. 吸油管路进气\n3. 泵轴承损坏\n4. 油液不足\n5. 过滤器堵塞\n6. 溢流阀振动\n\n### 故障树结构\n```\n顶事件：液压系统噪音过大\n├── OR\n│   ├── 泵噪音\n│   │   ├── OR\n│   │   │   ├── 泵内气蚀\n│   │   │   ├── 泵轴承损坏\n│   │   │   └── 泵磨损\n│   │   └── 泵安装松动\n│   ├── 进气问题\n│   │   ├── OR\n│   │   │   ├── 吸油管漏气\n│   │   │   ├── 油位过低\n│   │   │   └── 过滤器堵塞\n│   │   └── 空气进入\n│   ├── 溢流阀噪音\n│   │   ├── 阀芯振动\n│   │   └── 弹簧共振\n│   └── 液压缸噪音\n│       └── 空气进入液压缸\n```\n\n---\n\n## 7. 液压系统泄漏\n\n### 故障现象\n- 油箱液位下降快\n- 设备表面有油污\n- 压力不稳定');
-- TODO: 添加向量嵌入 (chunk_id: cf178aec-e2af-47ba-b103-6add6752eb76)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('e6452892-00f9-47d4-8982-906952b42cea', '5939e491-1522-4b87-95c7-10c36409530c', 9, 0, '### 故障现象\n- 油箱液位下降快\n- 设备表面有油污\n- 压力不稳定\n\n### 可能原因\n1. 密封件老化/损坏\n2. 管路连接松动\n3. 液压缸密封损坏\n4. 泵轴密封损坏\n5. 阀体泄漏\n6. 油箱焊缝泄漏\n\n### 故障树结构\n```\n顶事件：液压系统泄漏\n├── OR\n│   ├── 密封件泄漏\n│   │   ├── OR\n│   │   │   ├── 密封件老化\n│   │   │   ├── 密封件损坏\n│   │   │   └── 密封件安装不当\n│   │   └── 磨损\n│   ├── 管路泄漏\n│   │   ├── OR\n│   │   │   ├── 管路松动\n│   │   │   ├── 管路破裂\n│   │   │   └── 接头泄漏\n│   │   └── 硬管疲劳\n│   ├── 泵泄漏\n│   │   ├── 轴密封损坏\n│   │   └── 泵体裂纹\n│   └── 阀泄漏\n│       ├── 阀体泄漏\n│       └── 阀芯泄漏\n```');
-- TODO: 添加向量嵌入 (chunk_id: e6452892-00f9-47d4-8982-906952b42cea)

