INSERT INTO documents (doc_id, filename, file_type) VALUES ('8f573a55-3921-4d57-b601-0f94cde714c9', 'industrial_equipment_faults.md', 'markdown');

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('736c8283-9335-49c7-99cd-14c4602cb802', '8f573a55-3921-4d57-b601-0f94cde714c9', 0, 0, '# 工业设备故障知识库\n\n> 本文档包含常见工业设备的故障现象、原因分析及解决方案\n> 来源：行业标准和技术手册摘要\n\n---\n\n## 一、电动机故障\n\n### 1.1 电动机无法启动\n\n**故障现象**：接通电源后，电动机不转动或转动缓慢\n\n**可能原因**：\n1. 电源问题：缺相、电压过低、开关未闭合\n2. 绕组故障：绕组短路、断路、接地\n3. 机械故障：轴承损坏、转子卡死、负载过大\n4. 保护器故障：热继电器未复位、电机保护器跳闸\n\n**解决方案**：\n- 检查电源三相电压是否正常\n- 检测绕组绝缘电阻\n- 检查轴承和机械负载\n- 复位保护器\n\n### 1.2 电动机过热\n\n**故障现象**：电动机外壳温度超过额定值\n\n**可能原因**：\n1. 过载：负载超过额定功率\n2. 散热不良：风扇损坏或散热通道堵塞\n3. 电压异常：电压过高或过低\n4. 绕组问题：局部短路、绝缘老化\n\n**解决方案**：\n- 降低负载或更换更大功率电机\n- 清理散热通道，检查风扇\n- 调整电压至额定范围\n- 检修或更换绕组\n\n### 1.3 电动机振动过大\n\n**故障现象**：运行时振动异常，伴有异常声响');
-- TODO: 添加向量嵌入 (chunk_id: 736c8283-9335-49c7-99cd-14c4602cb802)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('cf980413-a68d-4f34-90cc-87b1211b7d58', '8f573a55-3921-4d57-b601-0f94cde714c9', 1, 0, '### 1.3 电动机振动过大\n\n**故障现象**：运行时振动异常，伴有异常声响\n\n**可能原因**：\n1. 机械不平衡：转子不平衡、联轴器不对中\n2. 轴承故障：磨损、损坏、润滑不良\n3. 电磁问题：气隙不均匀、绕组不对称\n\n**解决方案**：\n- 平衡转子，校准联轴器\n- 更换轴承，重新加注润滑脂\n- 检查并调整气隙\n\n### 1.4 电动机异响\n\n**故障现象**：运行时发出异常声响\n\n**可能原因**：\n1. 轴承故障：滚动体磨损、保持架损坏\n2. 气隙问题：定转子摩擦\n3. 螺栓松动：机座或端盖螺栓松动\n\n**解决方案**：\n- 检查更换轴承\n- 检查并调整气隙\n- 紧固所有螺栓\n\n---\n\n## 二、液压系统故障\n\n### 2.1 液压系统无压力\n\n**故障现象**：系统无法建立工作压力，执行机构不动\n\n**可能原因**：\n1. 泵故障：内磨损、电机不转、过滤器堵塞\n2. 油箱问题：油量不足、油液污染\n3. 阀组故障：溢流阀设定不当、阀芯卡滞\n4. 泄漏：管道泄漏、密封件损坏');
-- TODO: 添加向量嵌入 (chunk_id: cf980413-a68d-4f34-90cc-87b1211b7d58)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('78944de8-62e1-48e0-bd20-74e8b3467ad0', '8f573a55-3921-4d57-b601-0f94cde714c9', 2, 0, '**解决方案**：\n- 检查泵运行状态和油液量\n- 清洗或更换过滤器\n- 调整溢流阀压力\n- 检查并更换密封件\n\n### 2.2 液压系统压力不稳定\n\n**故障现象**：压力波动大，执行机构动作不平稳\n\n**可能原因**：\n1. 泵问题：变量机构故障、吸入空气\n2. 阀故障：阀芯磨损、弹簧疲劳\n3. 油液问题：空气混入、油温过高\n\n**解决方案**：\n- 检查泵的变量机构\n- 排除系统空气\n- 更换或修复阀门\n\n### 2.3 液压系统油温过高\n\n**故障现象**：油温超过正常工作范围（60-80°C）\n\n**可能原因**：\n1. 冷却不足：冷却器堵塞、水温高\n2. 泄漏：内泄漏导致效率降低\n3. 压力过高：系统压力调定过高\n\n**解决方案**：\n- 清洗冷却器，检查冷却水\n- 检查泄漏并修复\n- 调整系统压力\n\n### 2.4 液压执行机构动作缓慢\n\n**故障现象**：执行机构运动速度低于额定值\n\n**可能原因**：\n1. 流量不足：泵流量小、阀门开度小\n2. 压力不足：负载过大、泄漏\n3. 油液粘度过高：油温低、油品不对');
-- TODO: 添加向量嵌入 (chunk_id: 78944de8-62e1-48e0-bd20-74e8b3467ad0)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('6e2f00aa-5a86-462b-9602-e1e4e5be9cdb', '8f573a55-3921-4d57-b601-0f94cde714c9', 3, 0, '**解决方案**：\n- 检查泵流量和阀门开度\n- 检查泄漏并修复\n- 加热油液或更换合适粘度油品\n\n---\n\n## 三、PLC控制系统故障\n\n### 3.1 PLC无法启动\n\n**故障现象**：PLC上电后RUN灯不亮或闪烁\n\n**可能原因**：\n1. 电源故障：电源模块损坏、供电不稳\n2. 程序丢失：电池电量耗尽、干扰导致程序丢失\n3. CPU故障：处理器损坏\n\n**解决方案**：\n- 检查电源电压和模块状态\n- 更换电池并重新下载程序\n- 更换CPU模块\n\n### 3.2 PLC通讯故障\n\n**故障现象**：PLC与上位机或其他设备无法通讯\n\n**可能原因**：\n1. 通讯参数错误：波特率、数据位、校验位不匹配\n2. 通讯模块故障：模块损坏\n3. 物理连接问题：网线/RS485线缆损坏\n4. 地址冲突：设备地址重复\n\n**解决方案**：\n- 检查并统一通讯参数\n- 更换通讯模块\n- 检查并更换通讯线缆\n- 重新设定设备地址\n\n### 3.3 输入点无信号\n\n**故障现象**：输入点指示灯不亮，程序检测不到输入');
-- TODO: 添加向量嵌入 (chunk_id: 6e2f00aa-5a86-462b-9602-e1e4e5be9cdb)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('9c2ff98c-2639-401b-87d0-b035367e7ebf', '8f573a55-3921-4d57-b601-0f94cde714c9', 4, 0, '### 3.3 输入点无信号\n\n**故障现象**：输入点指示灯不亮，程序检测不到输入\n\n**可能原因**：\n1. 传感器故障：接近开关、按钮损坏\n2. 接线问题：线缆断开、接触不良\n3. 模块故障：输入模块损坏\n\n**解决方案**：\n- 检测传感器输出信号\n- 检查接线是否牢固\n- 更换输入模块\n\n### 3.4 输出点无动作\n\n**故障现象**：程序已驱动输出但执行器不动作\n\n**可能原因**：\n1. 输出模块故障：晶体管/继电器损坏\n2. 接线问题：线缆断开\n3. 执行器故障：电磁阀、接触器损坏\n4. 负载过大：超过模块输出容量\n\n**解决方案**：\n- 检测输出模块信号\n- 检查执行器电源\n- 更换损坏的输出模块或执行器\n\n---\n\n## 四、离心泵故障\n\n### 4.1 泵无法启动\n\n**故障现象**：启动时电机不转或立即跳闸\n\n**可能原因**：\n1. 电源故障：缺相、电压过低\n2. 电机故障：绕组短路、断路\n3. 机械卡死：轴承损坏、叶轮卡住\n4. 保护器跳闸：过载保护动作\n\n**解决方案**：\n- 检查电源和电机状态\n- 检查机械部分是否卡死\n- 复位保护器');
-- TODO: 添加向量嵌入 (chunk_id: 9c2ff98c-2639-401b-87d0-b035367e7ebf)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('f416a78e-a699-4d0e-9b3c-9ab4bad6c1c2', '8f573a55-3921-4d57-b601-0f94cde714c9', 5, 0, '**解决方案**：\n- 检查电源和电机状态\n- 检查机械部分是否卡死\n- 复位保护器\n\n### 4.2 泵流量不足\n\n**故障现象**：出口流量低于额定值\n\n**可能原因**：\n1. 汽蚀：入口压力过低\n2. 堵塞：叶轮或管道堵塞\n3. 泄漏：密封件损坏、管道泄漏\n4. 转速不足：电机转速低于额定\n\n**解决方案**：\n- 提高入口压力\n- 清理叶轮和管道\n- 更换密封件\n- 检查电机转速\n\n### 4.3 泵振动过大\n\n**故障现象**：运行时异常振动\n\n**可能原因**：\n1. 汽蚀：工作点偏离\n2. 轴承故障：磨损、损坏\n3. 不平衡：叶轮磨损不均匀\n4. 对中不良：联轴器对中误差大\n\n**解决方案**：\n- 调整工作点\n- 更换轴承\n- 平衡叶轮\n- 重新对中\n\n### 4.4 密封泄漏\n\n**故障现象**：机械密封处泄漏\n\n**可能原因**：\n1. 密封磨损：动环、静环磨损\n2. 弹簧疲劳：密封弹簧失效\n3. 介质问题：腐蚀性介质、温度过高\n\n**解决方案**：\n- 更换密封件\n- 选用耐腐蚀材质\n- 降低介质温度\n\n---\n\n## 五、变频器故障');
-- TODO: 添加向量嵌入 (chunk_id: f416a78e-a699-4d0e-9b3c-9ab4bad6c1c2)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('551708b3-88d3-46f2-993b-e7706fbd7279', '8f573a55-3921-4d57-b601-0f94cde714c9', 6, 0, '---\n\n## 五、变频器故障\n\n### 5.1 变频器过流\n\n**故障现象**：运行中报OC（过流）故障\n\n**可能原因**：\n1. 负载过大：超过变频器容量\n2. 加速时间过短：电机加速过快\n3. 电机故障：绕组短路、接地\n4. 输出短路：电缆损坏\n\n**解决方案**：\n- 降低负载或增大变频器容量\n- 增加加速时间\n- 检查电机绝缘\n- 检查输出电缆\n\n### 5.2 变频器过压\n\n**故障现象**：运行中报OV（过压）故障\n\n**可能原因**：\n1. 电源电压过高\n2. 减速时间过短\n3. 负载惯性过大\n4. 制动单元故障\n\n**解决方案**：\n- 检查输入电压\n- 增加减速时间\n- 使用制动电阻\n- 检查制动单元\n\n### 5.3 变频器过热\n\n**故障现象**：变频器报OH（过热）故障\n\n**可能原因**：\n1. 环境温度过高\n2. 散热风扇故障\n3. 散热片堵塞\n4. 负载过大\n\n**解决方案**：\n- 改善通风环境\n- 更换散热风扇\n- 清理散热片\n- 降低负载\n\n---\n\n## 六、故障诊断基本方法\n\n### 6.1 问');
-- TODO: 添加向量嵌入 (chunk_id: 551708b3-88d3-46f2-993b-e7706fbd7279)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('b68af027-a853-482f-85e3-af7a5dffaca5', '8f573a55-3921-4d57-b601-0f94cde714c9', 7, 0, '---\n\n## 六、故障诊断基本方法\n\n### 6.1 问\n\n- 故障发生前后的情况\n- 故障发生的频率\n- 是否有过维修或改造\n\n### 6.2 看\n\n- 外观检查：是否有泄漏、损坏、变色\n- 指示灯状态：运行、报警指示\n- 仪表读数：压力、温度、电流\n\n### 6.3 听\n\n- 异常声响：撞击、摩擦、啸叫\n- 运行声音是否平稳\n\n### 6.4 触\n\n- 振动是否正常\n- 温度是否异常\n- 紧固件是否松动\n\n### 6.5 测\n\n- 电压、电流测量\n- 压力、流量测量\n- 绝缘电阻测量\n\n---\n\n*本知识库可作为故障树分析的参考依据*');
-- TODO: 添加向量嵌入 (chunk_id: b68af027-a853-482f-85e3-af7a5dffaca5)

