INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('c3713c90-b123-4dfc-af50-6a518866e349', 'e1dff10d-b436-4967-9653-3da88f9561ad', 0, 0, '# 电机故障知识库\n\n## 1. 电机无法启动\n\n### 故障现象\n- 按下启动按钮，电机不转\n- 电机发出嗡嗡声但不转动\n- 电机保护器跳闸\n\n### 可能原因（按概率排序）\n1. 电源故障（缺相、电压过低）\n2. 电机绕组短路或开路\n3. 轴承损坏导致转子卡死\n4. 负载过大（机械卡阻）\n5. 启动电容失效（单相电机）\n6. 控制电路故障（接触器、按钮）');
-- TODO: 添加向量嵌入 (chunk_id: c3713c90-b123-4dfc-af50-6a518866e349)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('f4f9124c-823e-4d0a-b02d-b80fdc52f160', 'e1dff10d-b436-4967-9653-3da88f9561ad', 1, 0, '### 故障树结构\n```\n顶事件：电机无法启动\n├── OR\n│   ├── 电源故障\n│   │   ├── AND\n│   │   │   ├── 缺相\n│   │   │   └── 接触器故障\n│   │   └── 电压过低\n│   ├── 电机本体故障\n│   │   ├── OR\n│   │   │   ├── 绕组短路\n│   │   │   └── 绕组开路\n│   │   └── 轴承损坏\n│   ├── 负载过大\n│   │   ├── AND\n│   │   │   ├── 机械卡阻\n│   │   │   └── 润滑不良\n│   │   └── 负载过载\n│   └── 控制电路故障\n│       ├── OR\n│       │   ├── 启动按钮故障\n│       │   └── 停止按钮故障\n│       └── 接触器故障\n```\n\n### 维修建议\n1. 检查电源电压和接线\n2. 测量电机绕组电阻\n3. 检查轴承转动是否灵活\n4. 检查负载情况\n5. 检查控制电路\n\n---\n\n## 2. 电机运行异常（振动/噪音）');
-- TODO: 添加向量嵌入 (chunk_id: f4f9124c-823e-4d0a-b02d-b80fdc52f160)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('f84a9b2b-cf65-4f33-8027-8db4ee52804e', 'e1dff10d-b436-4967-9653-3da88f9561ad', 2, 0, '---\n\n## 2. 电机运行异常（振动/噪音）\n\n### 故障现象\n- 电机振动过大\n- 异常噪音（嗡嗡声、啸叫声）\n- 轴承部位温度过高\n\n### 可能原因\n1. 轴承磨损或损坏\n2. 转子不平衡\n3. 基础松动\n4. 绕组松动\n5. 冷却风扇故障\n\n### 故障树结构\n```\n顶事件：电机运行异常\n├── OR\n│   ├── 轴承故障\n│   │   ├── OR\n│   │   │   ├── 轴承磨损\n│   │   │   ├── 轴承损坏\n│   │   │   └── 润滑不良\n│   │   └── 轴承温度过高\n│   ├── 机械问题\n│   │   ├── OR\n│   │   │   ├── 转子不平衡\n│   │   │   └── 基础松动\n│   │   └── 对中不良\n│   └── 电气问题\n│       ├── OR\n│       │   ├── 绕组松动\n│       │   └── 冷却风扇故障\n│       └── 电源谐波\n```\n\n---\n\n## 3. 电机过热');
-- TODO: 添加向量嵌入 (chunk_id: f84a9b2b-cf65-4f33-8027-8db4ee52804e)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('a8ec22a5-78dc-47c6-b707-4722fd92de2d', 'e1dff10d-b436-4967-9653-3da88f9561ad', 3, 0, '---\n\n## 3. 电机过热\n\n### 故障现象\n- 电机表面温度过高\n- 保护器报警\n- 绝缘老化加速\n\n### 可能原因\n1. 负载过大（长时间过载）\n2. 通风散热不良\n3. 电源电压异常\n4. 电机内部故障（绕组短路）\n5. 环境温度过高');
-- TODO: 添加向量嵌入 (chunk_id: a8ec22a5-78dc-47c6-b707-4722fd92de2d)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('1a416d59-c098-4d81-b831-f3ca86d737da', 'e1dff10d-b436-4967-9653-3da88f9561ad', 4, 0, '### 故障树结构\n```\n顶事件：电机过热\n├── OR\n│   ├── 过载运行\n│   │   ├── AND\n│   │   │   ├── 负载过大\n│   │   │   └── 运行时间过长\n│   │   └── 频繁启动\n│   ├── 散热不良\n│   │   ├── OR\n│   │   │   ├── 冷却风扇故障\n│   │   │   └── 散热片堵塞\n│   │   └── 环境温度过高\n│   ├── 电源问题\n│   │   ├── OR\n│   │   │   ├── 电压过高\n│   │   │   └── 电压过低\n│   │   └── 缺相运行\n│   └── 电机内部故障\n│       ├── OR\n│       │   ├── 绕组局部短路\n│       │   └── 绝缘老化\n│       └── 匝间短路\n```\n\n---\n\n## 4. 电机转速异常\n\n### 故障现象\n- 转速低于额定值\n- 转速不稳定\n- 转速过高');
-- TODO: 添加向量嵌入 (chunk_id: 1a416d59-c098-4d81-b831-f3ca86d737da)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('8d3d564d-9833-4e43-9514-c666220929a4', 'e1dff10d-b436-4967-9653-3da88f9561ad', 5, 0, '## 4. 电机转速异常\n\n### 故障现象\n- 转速低于额定值\n- 转速不稳定\n- 转速过高\n\n### 可能原因\n1. 电源频率异常\n2. 负载过大\n3. 变频器参数设置错误\n4. 电机绕组故障\n5. 转子断条\n\n### 故障树结构\n```\n顶事件：电机转速异常\n├── OR\n│   ├── 转速过低\n│   │   ├── OR\n│   │   │   ├── 电源电压低\n│   │   │   └── 电源频率低\n│   │   ├── 负载过大\n│   │   └── 变频器故障\n│   ├── 转速不稳定\n│   │   ├── OR\n│   │   │   ├── 负载波动\n│   │   │   └── 电源不稳\n│   │   └── 变频器参数不当\n│   └── 转速过高\n│       ├── 电源频率过高\n│       └── 变频器参数错误\n```\n\n---\n\n## 5. 电机漏电\n\n### 故障现象\n- 电机外壳带电\n- 接地保护器动作\n- 绝缘电阻低\n\n### 可能原因\n1. 绕组绝缘损坏\n2. 接线盒进水\n3. 电缆破损\n4. 环境潮湿');
-- TODO: 添加向量嵌入 (chunk_id: 8d3d564d-9833-4e43-9514-c666220929a4)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('ead0c71f-1ea1-4222-a0bc-465fffee7c6c', 'e1dff10d-b436-4967-9653-3da88f9561ad', 6, 0, '### 可能原因\n1. 绕组绝缘损坏\n2. 接线盒进水\n3. 电缆破损\n4. 环境潮湿\n\n### 故障树结构\n```\n顶事件：电机漏电\n├── OR\n│   ├── 绕组绝缘故障\n│   │   ├── OR\n│   │   │   ├── 绕组老化\n│   │   │   ├── 绕组烧毁\n│   │   │   └── 绕组受潮\n│   │   └── 匝间短路\n│   ├── 外部损伤\n│   │   ├── OR\n│   │   │   ├── 电缆破损\n│   │   │   └── 接线盒进水\n│   │   └── 机械损伤\n│   └── 环境因素\n│       └── 潮湿环境\n```');
-- TODO: 添加向量嵌入 (chunk_id: ead0c71f-1ea1-4222-a0bc-465fffee7c6c)

