INSERT INTO documents (doc_id, filename, file_type) VALUES ('67b5675e-c3ff-4fb7-a232-73a1530e29ba', 'plc_faults.md', 'markdown');

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('985492dd-5476-40d4-82a2-599c07ebc4e8', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 0, 0, '# PLC控制系统故障知识库\n\n## 1. PLC无法启动/死机\n\n### 故障现象\n- PLC上电后RUN灯不亮\n- PLC状态指示异常\n- 程序无法运行\n- 频繁重启\n\n### 可能原因\n1. 电源故障（电源模块损坏、电压不稳）\n2. CPU故障（CPU损坏、过热）\n3. 存储器故障（程序丢失、内存损坏）\n4. 固件损坏\n5. 干扰信号（电磁干扰、静电）\n6. 扩展模块故障');
-- TODO: 添加向量嵌入 (chunk_id: 985492dd-5476-40d4-82a2-599c07ebc4e8)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('63390f1c-c1d2-4cd9-b576-e0c8558fe8cd', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 1, 0, '### 故障树结构\n```\n顶事件：PLC无法启动\n├── OR\n│   ├── 电源问题\n│   │   ├── OR\n│   │   │   ├── 电源模块损坏\n│   │   │   ├── 输入电压异常\n│   │   │   └── 电源接线松动\n│   │   └── 电源过载\n│   ├── CPU故障\n│   │   ├── OR\n│   │   │   ├── CPU过热\n│   │   │   ├── CPU损坏\n│   │   │   └── CPU接触不良\n│   │   └── 固件损坏\n│   ├── 存储器故障\n│   │   ├── OR\n│   │   │   ├── 程序丢失\n│   │   │   ├── 内存损坏\n│   │   │   └── 电池电量不足\n│   │   └── 存储卡故障\n│   └── 干扰问题\n│       ├── OR\n│       │   ├── 电磁干扰\n│       │   ├── 静电放电\n│       │   └── 信号线干扰\n│       └── 接地不良\n```\n\n---');
-- TODO: 添加向量嵌入 (chunk_id: 63390f1c-c1d2-4cd9-b576-e0c8558fe8cd)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('b5f44eac-8cb4-4564-bc3d-cda9d0e8bb06', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 2, 0, '---\n\n## 2. PLC通讯故障\n\n### 故障现象\n- 无法与上位机通讯\n- 触摸屏无响应\n- 远程I/O掉线\n- 通讯频繁中断\n\n### 可能原因\n1. 通讯参数设置错误（波特率、数据位等）\n2. 通讯电缆损坏\n3. 通讯接口损坏\n4. 网络配置错误（IP地址冲突）\n5. 干扰信号\n6. 设备地址冲突');
-- TODO: 添加向量嵌入 (chunk_id: b5f44eac-8cb4-4564-bc3d-cda9d0e8bb06)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('fa9c3150-68df-414f-9168-207bf7ba1ed0', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 3, 0, '### 故障树结构\n```\n顶事件：PLC通讯故障\n├── OR\n│   ├── 参数设置错误\n│   │   ├── OR\n│   │   │   ├── 波特率不匹配\n│   │   │   ├── 数据位错误\n│   │   │   └── 校验方式错误\n│   │   └── 通讯协议错误\n│   ├── 硬件故障\n│   │   ├── OR\n│   │   │   ├── 通讯口损坏\n│   │   │   ├── 通讯电缆损坏\n│   │   │   └── 连接器松动\n│   │   └── 网卡故障\n│   ├── 网络问题\n│   │   ├── OR\n│   │   │   ├── IP地址冲突\n│   │   │   ├── 子网掩码错误\n│   │   │   └── 网关设置错误\n│   │   └── 交换机故障\n│   └── 干扰问题\n│       └── 通讯线干扰\n```\n\n---\n\n## 3. 输入点无响应\n\n### 故障现象\n- 输入信号已变化但PLC无响应\n- 状态指示灯不亮\n- 程序无法检测到输入');
-- TODO: 添加向量嵌入 (chunk_id: fa9c3150-68df-414f-9168-207bf7ba1ed0)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('66d73747-4c88-4887-b169-aadfcf394b88', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 4, 0, '### 故障现象\n- 输入信号已变化但PLC无响应\n- 状态指示灯不亮\n- 程序无法检测到输入\n\n### 可能原因\n1. 输入模块损坏\n2. 接线松动/断开\n3. 传感器故障\n4. 电源问题（输入电源丢失）\n5. 地址设置错误');
-- TODO: 添加向量嵌入 (chunk_id: 66d73747-4c88-4887-b169-aadfcf394b88)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('ceb7f444-8c86-4ceb-b17b-7eee3ef4a52d', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 5, 0, '### 故障树结构\n```\n顶事件：输入点无响应\n├── OR\n│   ├── 输入模块故障\n│   │   ├── OR\n│   │   │   ├── 输入点损坏\n│   │   │   └── 模块内部故障\n│   │   └── 模块电源故障\n│   ├── 接线问题\n│   │   ├── OR\n│   │   │   ├── 接线松动\n│   │   │   ├── 接线断开\n│   │   │   └── 接线错误\n│   │   └── 端子松动\n│   ├── 传感器故障\n│   │   ├── OR\n│   │   │   ├── 传感器损坏\n│   │   │   ├── 传感器电源故障\n│   │   │   └── 传感器类型不匹配\n│   │   └── 传感器安装错误\n│   └── 参数设置错误\n│       └── 输入地址错误\n```\n\n---\n\n## 4. 输出点无动作\n\n### 故障现象\n- 程序已触发但输出点无动作\n- 输出指示灯不亮\n- 负载不动作');
-- TODO: 添加向量嵌入 (chunk_id: ceb7f444-8c86-4ceb-b17b-7eee3ef4a52d)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('056fe454-3d65-468b-b40f-29d2091908dc', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 6, 0, '### 故障现象\n- 程序已触发但输出点无动作\n- 输出指示灯不亮\n- 负载不动作\n\n### 可能原因\n1. 输出模块损坏\n2. 负载电源故障\n3. 接线断开\n4. 负载故障（接触器、继电器损坏）\n5. 保护电路动作（短路保护）');
-- TODO: 添加向量嵌入 (chunk_id: 056fe454-3d65-468b-b40f-29d2091908dc)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('5778f1b8-f1e9-4fd5-b98d-c2ab43e32471', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 7, 0, '### 故障树结构\n```\n顶事件：输出点无动作\n├── OR\n│   ├── 输出模块故障\n│   │   ├── OR\n│   │   │   ├── 输出点损坏\n│   │   │   └── 模块内部故障\n│   │   └── 模块过载损坏\n│   ├── 负载电源问题\n│   │   ├── OR\n│   │   │   ├── 负载电源丢失\n│   │   │   └── 负载电压不足\n│   │   └── 保险丝熔断\n│   ├── 接线问题\n│   │   ├── OR\n│   │   │   ├── 接线松动\n│   │   │   └── 接线断开\n│   │   └── 端子松动\n│   └── 负载故障\n│       ├── OR\n│       │   ├── 接触器故障\n│       │   ├── 继电器故障\n│       │   └── 负载短路\n│       └── 负载过载保护\n```\n\n---\n\n## 5. 程序运行异常\n\n### 故障现象\n- 程序逻辑执行错误\n- 定时器/计数器不准确\n- 数据处理错误\n- 扫描时间过长');
-- TODO: 添加向量嵌入 (chunk_id: 5778f1b8-f1e9-4fd5-b98d-c2ab43e32471)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('d736d239-f05a-46b1-8933-79ba3fca1078', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 8, 0, '### 可能原因\n1. 程序逻辑错误\n2. 扫描周期过长\n3. 数据类型不匹配\n4. 内存区域冲突\n5. 干扰导致数据错误\n\n### 故障树结构\n```\n顶事件：程序运行异常\n├── OR\n│   ├── 程序错误\n│   │   ├── OR\n│   │   │   ├── 逻辑错误\n│   │   │   ├── 定时器设置错误\n│   │   │   └── 计数器设置错误\n│   │   └── 指令使用错误\n│   ├── 扫描周期问题\n│   │   ├── OR\n│   │   │   ├── 扫描时间过长\n│   │   │   ├── 程序过于复杂\n│   │   │   └── 频繁中断\n│   │   └── 通讯占用时间过长\n│   ├── 数据问题\n│   │   ├── OR\n│   │   │   ├── 数据类型错误\n│   │   │   ├── 数据溢出\n│   │   │   └── 数据区冲突\n│   │   └── 内存不足\n│   └── 干扰问题\n│       └── 数据被干扰\n```\n\n---\n\n## 6. 模拟量信号异常');
-- TODO: 添加向量嵌入 (chunk_id: d736d239-f05a-46b1-8933-79ba3fca1078)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('a062ea1b-3b29-4c92-b169-3fbb5f094c31', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 9, 0, '---\n\n## 6. 模拟量信号异常\n\n### 故障现象\n- 模拟量读数不稳定\n- 数值偏差大\n- 超出量程\n- 无信号\n\n### 可能原因\n1. 模拟量模块故障\n2. 传感器故障\n3. 接线问题（干扰、接地）\n4. 模块参数设置错误\n5. 信号转换器故障');
-- TODO: 添加向量嵌入 (chunk_id: a062ea1b-3b29-4c92-b169-3fbb5f094c31)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('d41627cf-02af-4885-917b-005865176122', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 10, 0, '### 故障树结构\n```\n顶事件：模拟量信号异常\n├── OR\n│   ├── 读数不稳定\n│   │   ├── OR\n│   │   │   ├── 信号干扰\n│   │   │   ├── 接地不良\n│   │   │   └── 接线松动\n│   │   └── 环境干扰\n│   ├── 数值偏差大\n│   │   ├── OR\n│   │   │   ├── 传感器零偏\n│   │   │   ├── 模块校准错误\n│   │   │   └── 量程设置错误\n│   │   └── 传感器老化\n│   ├── 无信号\n│   │   ├── OR\n│   │   │   ├── 传感器故障\n│   │   │   ├── 接线断开\n│   │   │   └── 模块故障\n│   │   └── 电源故障\n│   └── 超量程\n│       ├── 输入超量程\n│       └── 传感器故障\n```\n\n---\n\n## 7. PLC报警/错误\n\n### 故障现象\n- 报警灯亮\n- 错误代码显示\n- 系统停止运行');
-- TODO: 添加向量嵌入 (chunk_id: d41627cf-02af-4885-917b-005865176122)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('c3e5e17a-10f5-4383-8558-d5e588272b73', '67b5675e-c3ff-4fb7-a232-73a1530e29ba', 11, 0, '### 故障现象\n- 报警灯亮\n- 错误代码显示\n- 系统停止运行\n\n### 可能原因\n1. 系统错误（硬件故障）\n2. 程序错误（语法错误、地址错误）\n3. 通讯错误\n4. 电池电量低\n5. 内存错误\n\n### 故障树结构\n```\n顶事件：PLC报警/错误\n├── OR\n│   ├── 系统错误\n│   │   ├── OR\n│   │   │   ├── CPU错误\n│   │   │   ├── 内存错误\n│   │   │   └── 电源错误\n│   │   └── 硬件故障\n│   ├── 程序错误\n│   │   ├── OR\n│   │   │   ├── 语法错误\n│   │   │   ├── 地址错误\n│   │   │   └── 指令错误\n│   │   └── 程序循环错误\n│   ├── 通讯错误\n│   │   ├── 网络故障\n│   │   └── 设备离线\n│   └── 电池/存储错误\n│       ├── 电池电量低\n│       └── 存储卡错误\n```');
-- TODO: 添加向量嵌入 (chunk_id: c3e5e17a-10f5-4383-8558-d5e588272b73)

