INSERT INTO documents (doc_id, filename, file_type) VALUES ('f515a285-401d-4d65-8d78-2146f7020654', 'pump_faults.md', 'markdown');

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('a680e1c2-40e9-408e-8841-47be994fba0f', 'f515a285-401d-4d65-8d78-2146f7020654', 0, 0, '# 泵类设备故障知识库\n\n## 1. 离心泵无法启动\n\n### 故障现象\n- 启动时电机不转\n- 泵体振动异常\n- 有嗡嗡声但不运转\n\n### 可能原因\n1. 电源故障（缺相、电压低）\n2. 电机故障\n3. 轴承卡死\n4. 叶轮卡住\n5. 密封件粘连\n6. 出口阀门关闭');
-- TODO: 添加向量嵌入 (chunk_id: a680e1c2-40e9-408e-8841-47be994fba0f)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('408b0357-dd26-4732-8b5c-df97253cba4a', 'f515a285-401d-4d65-8d78-2146f7020654', 1, 0, '### 故障树结构\n```\n顶事件：离心泵无法启动\n├── OR\n│   ├── 电源问题\n│   │   ├── OR\n│   │   │   ├── 缺相\n│   │   │   ├── 电压过低\n│   │   │   └── 电源开关未合上\n│   │   └── 保险丝熔断\n│   ├── 电机故障\n│   │   ├── OR\n│   │   │   ├── 电机绕组烧毁\n│   │   │   └── 电机轴承损坏\n│   │   └── 电机过载保护跳闸\n│   ├── 机械卡阻\n│   │   ├── OR\n│   │   │   ├── 轴承损坏\n│   │   │   ├── 叶轮卡住\n│   │   │   └── 密封件粘连\n│   │   └── 异物堵塞\n│   └── 操作问题\n│       └── 出口阀门关闭\n```\n\n---\n\n## 2. 离心泵流量不足\n\n### 故障现象\n- 实际流量低于额定值\n- 出口压力低\n- 工艺参数无法满足');
-- TODO: 添加向量嵌入 (chunk_id: 408b0357-dd26-4732-8b5c-df97253cba4a)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('f5f3a474-1527-4654-b120-825f563c6565', 'f515a285-401d-4d65-8d78-2146f7020654', 2, 0, '### 故障现象\n- 实际流量低于额定值\n- 出口压力低\n- 工艺参数无法满足\n\n### 可能原因\n1. 泵转速不够\n2. 叶轮磨损\n3. 吸入管路漏气\n4. 过滤器堵塞\n5. 汽蚀现象\n6. 出口阀门开度不足\n\n### 故障树结构\n```\n顶事件：离心泵流量不足\n├── OR\n│   ├── 泵本身问题\n│   │   ├── OR\n│   │   │   ├── 叶轮磨损\n│   │   │   ├── 叶轮损坏\n│   │   │   └── 泵转速不够\n│   │   └── 泵效率下降\n│   ├── 吸入问题\n│   │   ├── OR\n│   │   │   ├── 吸入管漏气\n│   │   │   ├── 过滤器堵塞\n│   │   │   └── 吸入口堵塞\n│   │   └── 汽蚀\n│   ├── 出口问题\n│   │   ├── 阀门开度小\n│   │   └── 出口压力过高\n│   └── 液体问题\n│       └── 液体粘度不符\n```\n\n---\n\n## 3. 离心泵过载');
-- TODO: 添加向量嵌入 (chunk_id: f5f3a474-1527-4654-b120-825f563c6565)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('247d16df-e228-4fbf-9cc7-8ffbecf268b6', 'f515a285-401d-4d65-8d78-2146f7020654', 3, 0, '---\n\n## 3. 离心泵过载\n\n### 故障现象\n- 电机电流超过额定值\n- 电机发热严重\n- 保护器动作\n\n### 可能原因\n1. 流量过大（扬程不足）\n2. 泵轴与电机轴不同心\n3. 轴承损坏\n4. 填料压得过紧\n5. 液体粘度高于设计值\n\n### 故障树结构\n```\n顶事件：离心泵过载\n├── OR\n│   ├── 负载过大\n│   │   ├── AND\n│   │   │   ├── 流量过大\n│   │   │   └── 扬程不足\n│   │   └── 出口压力过高\n│   ├── 机械问题\n│   │   ├── OR\n│   │   │   ├── 轴承损坏\n│   │   │   ├── 轴弯曲\n│   │   │   └── 同心度偏差\n│   │   └── 填料过紧\n│   └── 液体问题\n│       └── 液体粘度过高\n```\n\n---\n\n## 4. 离心泵振动过大\n\n### 故障现象\n- 泵体振动超标\n- 异常噪音\n- 轴承温度升高');
-- TODO: 添加向量嵌入 (chunk_id: 247d16df-e228-4fbf-9cc7-8ffbecf268b6)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('3f2b5439-b883-4cd6-b580-b5cb5e64d5e3', 'f515a285-401d-4d65-8d78-2146f7020654', 4, 0, '## 4. 离心泵振动过大\n\n### 故障现象\n- 泵体振动超标\n- 异常噪音\n- 轴承温度升高\n\n### 可能原因\n1. 轴承磨损或损坏\n2. 叶轮不平衡\n3. 泵轴弯曲\n4. 基础松动\n5. 气蚀\n6. 汽蚀现象\n7. 管道应力\n\n### 故障树结构\n```\n顶事件：离心泵振动过大\n├── OR\n│   ├── 轴承故障\n│   │   ├── OR\n│   │   │   ├── 轴承磨损\n│   │   │   ├── 轴承损坏\n│   │   │   └── 润滑不良\n│   │   └── 轴承温度过高\n│   ├── 机械不平衡\n│   │   ├── OR\n│   │   │   ├── 叶轮不平衡\n│   │   │   ├── 泵轴弯曲\n│   │   │   └── 轴套磨损\n│   │   └── 转子动平衡不良\n│   ├── 基础问题\n│   │   ├── 基础松动\n│   │   └── 减震垫损坏\n│   └── 外部因素\n│       ├── 管道应力\n│       └── 气蚀\n```\n\n---\n\n## 5. 离心泵轴承温度过高');
-- TODO: 添加向量嵌入 (chunk_id: 3f2b5439-b883-4cd6-b580-b5cb5e64d5e3)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('0ad42398-fee4-45a8-af50-11708a9e870a', 'f515a285-401d-4d65-8d78-2146f7020654', 5, 0, '---\n\n## 5. 离心泵轴承温度过高\n\n### 故障现象\n- 轴承部位温度超标\n- 润滑脂融化\n- 轴承损坏\n\n### 可能原因\n1. 润滑不良（缺油、油质差）\n2. 轴承安装不当\n3. 轴承磨损\n4. 冷却不良\n5. 过载运行\n\n### 故障树结构\n```\n顶事件：离心泵轴承温度过高\n├── OR\n│   ├── 润滑问题\n│   │   ├── OR\n│   │   │   ├── 润滑脂不足\n│   │   │   ├── 润滑脂变质\n│   │   │   └── 润滑脂过多\n│   │   └── 油质污染\n│   ├── 轴承问题\n│   │   ├── OR\n│   │   │   ├── 轴承磨损\n│   │   │   ├── 轴承安装不当\n│   │   │   └── 轴承损坏\n│   │   └── 轴承间隙过小\n│   ├── 冷却问题\n│   │   └── 冷却不良\n│   └── 运行问题\n│       └── 长期过载\n```\n\n---\n\n## 6. 离心泵密封泄漏\n\n### 故障现象\n- 轴封处泄漏\n- 泄漏量逐渐增大\n- 密封处有明显痕迹');
-- TODO: 添加向量嵌入 (chunk_id: 0ad42398-fee4-45a8-af50-11708a9e870a)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('3cbb3025-1af1-4822-9877-1b77d6745a6f', 'f515a285-401d-4d65-8d78-2146f7020654', 6, 0, '### 故障现象\n- 轴封处泄漏\n- 泄漏量逐渐增大\n- 密封处有明显痕迹\n\n### 可能原因\n1. 机械密封磨损\n2. 密封面划伤\n3. O型圈损坏\n4. 弹簧失效\n5. 泵轴磨损\n6. 安装不当\n\n### 故障树结构\n```\n顶事件：离心泵密封泄漏\n├── OR\n│   ├── 机械密封故障\n│   │   ├── OR\n│   │   │   ├── 密封面磨损\n│   │   │   ├── 密封面划伤\n│   │   │   └── 弹簧失效\n│   │   └── 密封面有杂质\n│   ├── 密封件损坏\n│   │   ├── OR\n│   │   │   ├── O型圈老化\n│   │   │   ├── O型圈损坏\n│   │   │   └── 垫片损坏\n│   │   └── 安装不当\n│   ├── 轴问题\n│   │   ├── 轴磨损\n│   │   └── 轴表面划伤\n│   └── 运行问题\n│       └── 长时间运行磨损\n```\n\n---\n\n## 7. 齿轮泵故障\n\n### 故障现象\n- 无流量输出\n- 流量不足\n- 噪音过大\n- 发热严重');
-- TODO: 添加向量嵌入 (chunk_id: 3cbb3025-1af1-4822-9877-1b77d6745a6f)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('886e728f-c92c-4b72-90af-4ca342f8f3fe', 'f515a285-401d-4d65-8d78-2146f7020654', 7, 0, '### 故障现象\n- 无流量输出\n- 流量不足\n- 噪音过大\n- 发热严重\n\n### 可能原因\n1. 齿轮磨损\n2. 侧板磨损\n3. 轴承损坏\n4. 油液粘度不当\n5. 入口堵塞\n\n### 故障树结构\n```\n顶事件：齿轮泵故障\n├── OR\n│   ├── 无流量\n│   │   ├── OR\n│   │   │   ├── 齿轮磨损严重\n│   │   │   ├── 侧板磨损\n│   │   │   └── 入口堵塞\n│   │   └── 转向错误\n│   ├── 流量不足\n│   │   ├── 齿轮磨损\n│   │   └── 侧板磨损\n│   ├── 噪音过大\n│   │   ├── OR\n│   │   │   ├── 轴承损坏\n│   │   │   ├── 齿轮磨损\n│   │   │   └── 油液有气泡\n│   │   └── 吸入空气\n│   └── 发热严重\n│       ├── 内部泄漏过大\n│       └── 油液粘度过高\n```\n\n---\n\n## 8. 螺杆泵故障\n\n### 故障现象\n- 不吸油\n- 流量不足\n- 振动噪音大\n- 轴功率过大');
-- TODO: 添加向量嵌入 (chunk_id: 886e728f-c92c-4b72-90af-4ca342f8f3fe)

INSERT INTO document_chunks (chunk_id, doc_id, chunk_index, page_num, text) VALUES ('a7abf052-f376-43ae-9bf1-99255d18df78', 'f515a285-401d-4d65-8d78-2146f7020654', 8, 0, '### 故障现象\n- 不吸油\n- 流量不足\n- 振动噪音大\n- 轴功率过大\n\n### 可能原因\n1. 螺杆磨损\n2. 衬套磨损\n3. 吸入条件不良\n4. 转速过高或过低\n5. 油液问题\n\n### 故障树结构\n```\n顶事件：螺杆泵故障\n├── OR\n│   ├── 不吸油\n│   │   ├── OR\n│   │   │   ├── 吸入管漏气\n│   │   │   ├── 液位过低\n│   │   │   └── 吸入过滤器堵塞\n│   │   └── 旋转方向错误\n│   ├── 流量不足\n│   │   ├── OR\n│   │   │   ├── 螺杆磨损\n│   │   │   ├── 衬套磨损\n│   │   │   └── 转速过低\n│   │   └── 内部泄漏\n│   ├── 振动噪音大\n│   │   ├── 螺杆磨损不均\n│   │   └── 轴承损坏\n│   └── 轴功率过大\n│       ├── 转速过高\n│       └── 液体粘度过高\n```');
